import React from "react";
import { Stop } from "@/types/stop";
import { DelayPrediction, LiveBusLocation } from "@/types/delay";

interface Props {
  stops: Stop[];
  predictions: DelayPrediction[];
  busLocations?: LiveBusLocation[];
}

const StopTimeline: React.FC<Props> = ({
  stops,
  predictions,
  busLocations = [],
}) => {
  const nextStopId = predictions[0]?.stopId;

  return (
    <div className="timeline">
      {stops.map((stop, index) => {
        const delay = predictions.find((p) => p.stopId === stop.id);
        const isPassed =
          delay && index < stops.findIndex((s) => s.id === nextStopId);
        const isNext = stop.id === nextStopId;

        return (
          <div
            key={stop.id}
            className={`stop-item 
              ${isPassed ? "passed" : ""} 
              ${isNext ? "next" : ""}`}
          >
            <div className="stop-marker"></div>

            <div className="stop-number">
              Stop {index + 1}
              {isNext ? " • Next Stop" : ""}
            </div>

            <div className="stop-header">
              <div className="stop-name">{stop.name}</div>

              <div className="stop-time">
                {delay ? (
                  <>
                    <span className={`eta ${isPassed ? "passed" : ""}`}>
                      {isPassed
                        ? `Departed`
                        : `In ${delay.predictedDelayMinutes} min`}
                    </span>
                    {delay.predictedDelayMinutes > 0 && !isPassed && (
                      <span
                        className={`delay ${
                          delay.predictedDelayMinutes >= 2 ? "high" : ""
                        }`}
                      >
                        +{delay.predictedDelayMinutes} min
                      </span>
                    )}
                  </>
                ) : (
                  <span className="eta">—</span>
                )}
              </div>
            </div>
          </div>
        );
      })}

      {/* Bus indicator block*/}
      {busLocations.length > 0 && (
        <div className="bus-position">
          <div className="bus-icon">🚌</div>
          <div className="bus-info">
            <div className="bus-number">Bus #{busLocations[0].busId}</div>
            <div className="bus-status">Currently Operating</div>
            <div className="between-stops">Bus is on route</div>
          </div>
        </div>
      )}
    </div>
  );
};

export default StopTimeline;
